message.content:
Ecco un thread pool RAII in C++20 con coda bounded, supporto per `std::future`, stop ordinato e gestione eccezioni:

```cpp
// thread_pool.hpp
#pragma once

#include <atomic>
#include <condition_variable>
#include <functional>
#include <future>
#include <memory>
#include <mutex>
#include <queue>
#include <stop_token>
#include <thread>
#include <vector>

class ThreadPool {
public:
    explicit ThreadPool(size_t num_threads, size_t max_queue_size = 64)
        : max_queue_size_(max_queue_size)
        , stop_source_(std::make_shared<std::stop_source>())
        , stop_token_(stop_source_->get_token())
    {
        workers_.reserve(num_threads);
        for (size_t i = 0; i < num_threads; ++i) {
            workers_.emplace_back([this, token = stop_token_]() {
                while (!token.stop_requested()) {
                    std::unique_lock lock(mutex_);
                    cv_.wait(lock, [this, &token] {
                        return token.stop_requested() || !queue_.empty();
                    });
                    if (token.stop_requested()) break;
                    auto task = std::move(queue_.front());
                    queue_.pop();
                    lock.unlock();
                    task();
                }
            });
        }
    }

    ~ThreadPool() {
        stop();
    }

    // Non-copyable, non-movable
    ThreadPool(const ThreadPool&) = delete;
    ThreadPool& operator=(const ThreadPool&) = delete;
    ThreadPool(ThreadPool&&) = delete;
    ThreadPool& operator=(ThreadPool&&) = delete;

    template <typename F, typename... Args>
    auto submit(F&& f, Args&&... args) -> std::future<decltype(f(args...))> {
        using ReturnType = decltype(f(args...));
        auto promise = std::make_shared<std::promise<ReturnType>>();
        auto future = promise->get_future();

        auto task = [promise = std::move(promise), func = std::bind(std::forward<F>(f), std::forward<Args>(args)...)]() {
            try {
                if constexpr (std::is_void_v<ReturnType>) {
                    func();
                    promise->set_value();
                } else {
                    promise->set_value(func());
                }
            } catch (...) {
                promise->set_exception(std::current_exception());
            }
        };

        {
            std::unique_lock lock(mutex_);
            cv_full_.wait(lock, [this] {
                return queue_.size() < max_queue_size_ || stop_token_.stop_requested();
            });
            if (stop_token_.stop_requested()) {
                throw std::runtime_error("ThreadPool is stopped");
            }
            queue_.emplace(std::move(task));
        }
        cv_.notify_one();
        return future;
    }

    void stop() {
        stop_source_->request_stop();
        cv_.notify_all();
        cv_full_.notify_all();
        for (auto& t : workers_) {
            if (t.joinable()) t.join();
        }
    }

    size_t queue_size() const {
        std::lock_guard lock(mutex_);
        return queue_.size();
    }

private:
    mutable std::mutex mutex_;
    std::condition_variable cv_;
    std::condition_variable cv_full_;
    std::queue<std::function<void()>> queue_;
    size_t max_queue_size_;
    std::vector<std::thread> workers_;
    std::shared_ptr<std::stop_source> stop_source_;
    std::stop_token stop_token_;
};
```

```cpp
// main.cpp - demo
#include "thread_pool.hpp"
#include <chrono>
#include <iostream>
#include <thread>

int main() {
    try {
        ThreadPool pool(4, 8); // 4 threads, max 8 tasks in queue

        // Submit work and get future
        auto future1 = pool.submit([](int a, int b) {
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
            return a + b;
        }, 5, 3);

        auto future2 = pool.submit([](int x) {
            return x * 2;
        }, 7);

        // Get results
        std::cout << "Result 1: " << future1.get() << std::endl; // 8
        std::cout << "Result 2: " << future2.get() << std::endl; // 14

        // Submit void task
        auto future3 = pool.submit([]() {
            std::cout << "Void task executed" << std::endl;
        });
        future3.get();

        // Exception handling demo
        auto future4 = pool.submit([]() -> int {
            throw std::runtime_error("Intentional error");
            return 0;
        });

        try {
            future4.get();
        } catch (const std::exception& e) {
            std::cout << "Caught exception: " << e.what() << std::endl;
        }

        // Queue full test
        for (int i = 0; i < 10; ++i) {
            pool.submit([i]() {
                std::this_thread::sleep_for(std::chrono::milliseconds(50));
                std::cout << "Task " << i << " completed" << std::endl;
            });
        }

        std::cout << "Queue size: " << pool.queue_size() << std::endl;

        // Stop is called automatically by destructor
        std::cout << "Demo completed successfully" << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }
    return 0;
}
```

**Caratteristiche principali:**

- **RAII**: Distruttore chiama `stop()` automaticamente
- **Coda bounded**: Limita il numero di task in coda (`max_queue_size`)
- **`std::future`**: Ogni `submit()` restituisce un future per ottenere il risultato
- **Stop ordinato**: Usa `std::stop_token` per arresto cooperativo
- **Gestione eccezioni**: Le eccezioni nei task vengono propagate al future
- **Thread-safe**: Mutex e condition variable per sincronizzazione

**Come compilare ed eseguire:**
```bash
g++ -std=c++20 -pthread main.cpp -o threadpool_demo && ./threadpool_demo
```
